"use client";

import * as React from "react";
import { cn } from "../lib/cn";

export type AutocompleteOption = {
  description?: React.ReactNode;
  disabled?: boolean;
  label: string;
  value: string;
};

export type AutocompleteProps = Omit<
  React.InputHTMLAttributes<HTMLInputElement>,
  "defaultValue" | "onChange" | "value"
> & {
  defaultValue?: string;
  emptyText?: React.ReactNode;
  listClassName?: string;
  onOptionSelect?: (option: AutocompleteOption) => void;
  onValueChange?: (value: string, option?: AutocompleteOption) => void;
  optionClassName?: string;
  options: readonly AutocompleteOption[];
  value?: string;
};

export const Autocomplete = React.forwardRef<HTMLInputElement, AutocompleteProps>(
  (
    {
      className,
      defaultValue = "",
      disabled,
      emptyText = "No matches found.",
      listClassName,
      onBlur,
      onFocus,
      onKeyDown,
      onOptionSelect,
      onValueChange,
      optionClassName,
      options,
      placeholder = "Search...",
      value,
      ...props
    },
    ref
  ) => {
    const [internalValue, setInternalValue] = React.useState(defaultValue);
    const [open, setOpen] = React.useState(false);
    const [highlightedIndex, setHighlightedIndex] = React.useState(0);
    const rootRef = React.useRef<HTMLSpanElement | null>(null);
    const inputRef = React.useRef<HTMLInputElement | null>(null);
    const listboxId = React.useId();
    const inputValue = value ?? internalValue;
    const filteredOptions = React.useMemo(
      () => filterOptions(options, inputValue),
      [inputValue, options]
    );
    const activeOption = filteredOptions[highlightedIndex];
    const activeOptionId = activeOption
      ? `${listboxId}-option-${highlightedIndex}`
      : undefined;

    React.useImperativeHandle(ref, () => inputRef.current as HTMLInputElement);

    React.useEffect(() => {
      setHighlightedIndex(getNextEnabledIndex(filteredOptions, 0, 1));
    }, [filteredOptions]);

    React.useEffect(() => {
      if (!open) return undefined;

      function handlePointerDown(event: PointerEvent) {
        if (!rootRef.current?.contains(event.target as Node)) setOpen(false);
      }

      function handleKeyDown(event: KeyboardEvent) {
        if (event.key === "Escape") setOpen(false);
      }

      window.addEventListener("pointerdown", handlePointerDown);
      window.addEventListener("keydown", handleKeyDown);
      return () => {
        window.removeEventListener("pointerdown", handlePointerDown);
        window.removeEventListener("keydown", handleKeyDown);
      };
    }, [open]);

    function setInputValue(nextValue: string, option?: AutocompleteOption) {
      if (value === undefined) setInternalValue(nextValue);
      onValueChange?.(nextValue, option);
    }

    function commitOption(option: AutocompleteOption) {
      if (option.disabled) return;
      setInputValue(option.label, option);
      onOptionSelect?.(option);
      setOpen(false);
      inputRef.current?.focus();
    }

    function moveHighlight(direction: 1 | -1) {
      const nextIndex = getNextEnabledIndex(filteredOptions, highlightedIndex + direction, direction);
      if (nextIndex >= 0) setHighlightedIndex(nextIndex);
    }

    return (
      <span className="relative block w-full min-w-0" ref={rootRef}>
        <span className="pointer-events-none absolute left-3 top-1/2 z-[1] h-4 w-4 -translate-y-1/2 rounded-full border-2 border-axie-muted/64 after:absolute after:-bottom-1 after:-right-1 after:h-2 after:w-0.5 after:rotate-[-45deg] after:rounded-full after:bg-axie-muted/64" />
        <input
          aria-activedescendant={open ? activeOptionId : undefined}
          aria-autocomplete="list"
          aria-controls={listboxId}
          aria-expanded={open}
          className={cn(
            "min-h-12 w-full rounded-axie-control border border-axie-line bg-axie-surface-soft px-axie-md pl-10 text-[16px] font-bold text-axie-ink outline-none transition-[background-color,border-color,box-shadow,transform] duration-300 ease-[var(--axie-motion-spring)] placeholder:text-axie-muted/52 focus:-translate-y-px focus:border-axie-accent/55 focus:bg-axie-surface focus:ring-2 focus:ring-axie-accent/16 disabled:cursor-not-allowed disabled:opacity-55 disabled:focus:translate-y-0",
            open && "border-axie-accent/55 bg-axie-surface ring-2 ring-axie-accent/16",
            className
          )}
          disabled={disabled}
          placeholder={placeholder}
          ref={inputRef}
          role="combobox"
          value={inputValue}
          onBlur={onBlur}
          onChange={(event) => {
            setInputValue(event.currentTarget.value);
            setOpen(true);
          }}
          onFocus={(event) => {
            onFocus?.(event);
            if (!disabled) setOpen(true);
          }}
          onKeyDown={(event) => {
            onKeyDown?.(event);
            if (event.defaultPrevented || disabled) return;
            if (event.key === "ArrowDown" || event.key === "ArrowUp") {
              event.preventDefault();
              if (!open) setOpen(true);
              moveHighlight(event.key === "ArrowDown" ? 1 : -1);
            }
            if (event.key === "Enter" && open) {
              event.preventDefault();
              const option = filteredOptions[highlightedIndex];
              if (option) commitOption(option);
            }
            if (event.key === "Escape") {
              setOpen(false);
            }
          }}
          {...props}
        />
        {open ? (
          <div
            className={cn(
              "absolute left-0 right-0 top-[calc(100%+8px)] z-30 grid max-h-72 min-w-0 gap-1.5 overflow-y-auto rounded-[14px] border border-axie-line bg-axie-surface p-2 text-axie-ink shadow-[0_20px_54px_color-mix(in_srgb,var(--axie-color-ink)_14%,transparent)] axie-pop",
              listClassName
            )}
            id={listboxId}
            role="listbox"
          >
            {filteredOptions.length ? (
              filteredOptions.map((option, index) => {
                const highlighted = index === highlightedIndex;

                return (
                  <button
                    aria-disabled={option.disabled || undefined}
                    aria-selected={highlighted}
                    className={cn(
                      "grid min-h-12 w-full grid-cols-[minmax(0,1fr)_auto] items-center gap-3 rounded-[12px] px-4 py-3 text-left outline-none transition-[background-color,color,transform] duration-200 ease-[var(--axie-motion-spring)]",
                      option.disabled
                        ? "cursor-not-allowed text-axie-muted/42"
                        : "cursor-pointer text-axie-ink hover:bg-axie-surface-soft/72 active:scale-[0.99]",
                      highlighted && !option.disabled && "bg-axie-accent-soft",
                      optionClassName
                    )}
                    disabled={option.disabled}
                    id={`${listboxId}-option-${index}`}
                    key={option.value}
                    role="option"
                    type="button"
                    onClick={() => commitOption(option)}
                    onMouseEnter={() => setHighlightedIndex(index)}
                  >
                    <span className="grid min-w-0 gap-0.5">
                      <span className="truncate text-[14px] font-black leading-5">
                        {option.label}
                      </span>
                      {option.description ? (
                        <span className="truncate text-[12px] font-bold leading-4 text-axie-muted">
                          {option.description}
                        </span>
                      ) : null}
                    </span>
                    <span className="font-mono text-[11px] font-black uppercase text-axie-muted/58">
                      {option.value}
                    </span>
                  </button>
                );
              })
            ) : (
              <div className="px-3 py-8 text-center text-[13px] font-bold text-axie-muted">
                {emptyText}
              </div>
            )}
          </div>
        ) : null}
      </span>
    );
  }
);

Autocomplete.displayName = "Autocomplete";

function filterOptions(options: readonly AutocompleteOption[], query: string) {
  const normalizedQuery = query.trim().toLowerCase();
  if (!normalizedQuery) return [...options];
  return options.filter((option) => {
    const description =
      typeof option.description === "string" || typeof option.description === "number"
        ? String(option.description)
        : "";
    return `${option.label} ${option.value} ${description}`
      .toLowerCase()
      .includes(normalizedQuery);
  });
}

function getNextEnabledIndex(
  options: readonly AutocompleteOption[],
  startIndex: number,
  direction: 1 | -1
) {
  if (!options.length) return -1;
  for (let offset = 0; offset < options.length; offset += 1) {
    const index = (startIndex + offset * direction + options.length) % options.length;
    if (!options[index]?.disabled) return index;
  }
  return -1;
}

type ClassValue = string | false | null | undefined;

export function cn(...values: ClassValue[]) {
  return values.filter(Boolean).join(" ");
}

@theme inline {
  --color-axie-ink: var(--axie-color-ink);
  --color-axie-paper: var(--axie-color-paper);
  --color-axie-surface: var(--axie-color-surface);
  --color-axie-surface-soft: var(--axie-color-surface-soft);
  --color-axie-muted: var(--axie-color-muted);
  --color-axie-line: var(--axie-color-line);
  --color-axie-accent: var(--axie-color-accent);
  --color-axie-accent-soft: var(--axie-color-accent-soft);
  --color-axie-danger: var(--axie-color-danger);
  --color-axie-danger-soft: var(--axie-color-danger-soft);
  --color-axie-warning: var(--axie-color-warning);
  --color-axie-warning-soft: var(--axie-color-warning-soft);
  --color-axie-info: var(--axie-color-info);
  --color-axie-info-soft: var(--axie-color-info-soft);
  --radius-axie-card: var(--axie-radius-card);
  --radius-axie-control: var(--axie-radius-control);
  --radius-axie-sheet: var(--axie-radius-sheet);
  --radius-axie-pill: var(--axie-radius-pill);
  --spacing-axie-page: var(--axie-space-page);
  --spacing-axie-xs: var(--axie-space-xs);
  --spacing-axie-sm: var(--axie-space-sm);
  --spacing-axie-md: var(--axie-space-md);
  --spacing-axie-lg: var(--axie-space-lg);
  --spacing-axie-xl: var(--axie-space-xl);
  --spacing-axie-2xl: var(--axie-space-2xl);
  --shadow-axie-raised: 0 16px 36px color-mix(in srgb, var(--axie-color-ink) 10%, transparent);
  --shadow-axie-soft: 0 10px 24px color-mix(in srgb, var(--axie-color-ink) 6%, transparent);
  --shadow-axie-nav: 0 16px 38px color-mix(in srgb, var(--axie-color-ink) 12%, transparent);
}

:root {
  --axie-color-ink: #28231f;
  --axie-color-paper: #f7f2ea;
  --axie-color-surface: #fffdf7;
  --axie-color-surface-soft: #eee6d9;
  --axie-color-muted: #766d62;
  --axie-color-line: #ddd0be;
  --axie-color-accent: #3f665c;
  --axie-color-accent-soft: #dde9e3;
  --axie-color-danger: #a44f43;
  --axie-color-danger-soft: #f0d8d2;
  --axie-color-warning: #967032;
  --axie-color-warning-soft: #eedfc2;
  --axie-color-info: #4f6a7f;
  --axie-color-info-soft: #dde7ed;
  --axie-radius-card: 10px;
  --axie-radius-control: 12px;
  --axie-radius-sheet: 30px;
  --axie-radius-pill: 999px;
  --axie-space-page: 20px;
  --axie-space-xs: 6px;
  --axie-space-sm: 10px;
  --axie-space-md: 14px;
  --axie-space-lg: 20px;
  --axie-space-xl: 28px;
  --axie-space-2xl: 36px;
  --axie-motion-fast: 160ms;
  --axie-motion-base: 240ms;
  --axie-motion-slow: 360ms;
  --axie-motion-ease: cubic-bezier(0.2, 0.9, 0.2, 1);
  --axie-motion-spring: cubic-bezier(0.16, 1, 0.3, 1);
  --axie-motion-pop: cubic-bezier(0.18, 1.24, 0.3, 1);
}

.axie-pressable {
  transform: translate3d(0, 0, 0) scale(1);
  transition-duration: var(--axie-motion-base);
  transition-property: background-color, border-color, box-shadow, color, opacity, transform;
  transition-timing-function: var(--axie-motion-spring);
  will-change: transform;
}

.axie-pressable:hover {
  transform: translate3d(0, -1px, 0) scale(1.005);
}

.axie-pressable:active {
  transform: translate3d(0, 0, 0) scale(0.985);
}

.axie-enter {
  animation: axie-enter var(--axie-motion-slow) var(--axie-motion-spring) both;
}

.axie-pop {
  animation: axie-pop var(--axie-motion-slow) var(--axie-motion-pop) both;
}

.axie-fade {
  animation: axie-fade var(--axie-motion-base) ease-out both;
}

.axie-sheet-backdrop {
  animation: axie-fade var(--axie-motion-fast) ease-out both;
}

.axie-sheet-panel {
  animation: axie-sheet-panel-in var(--axie-motion-slow) var(--axie-motion-ease) both;
}

.axie-row-enter {
  animation: axie-row-in var(--axie-motion-base) var(--axie-motion-ease) both;
  animation-delay: var(--axie-row-delay, 0ms);
}

@keyframes axie-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes axie-enter {
  from {
    opacity: 0;
    transform: translate3d(0, 10px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-pop {
  from {
    opacity: 0;
    transform: translate3d(0, 12px, 0) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-sheet-panel-in {
  from {
    opacity: 0.72;
    transform: translate3d(0, 26px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-row-in {
  from {
    opacity: 0;
    transform: translate3d(0, 8px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-accordion-down {
  from {
    opacity: 0;
    transform: translate3d(0, -4px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-shimmer {
  100% {
    transform: translateX(100%);
  }
}

@keyframes axie-pulse-dot {
  0%,
  100% {
    box-shadow: 0 0 0 0 color-mix(in srgb, var(--axie-color-accent) 30%, transparent);
  }
  50% {
    box-shadow: 0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 0%, transparent);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-duration: 0.001ms !important;
  }

  .axie-enter,
  .axie-pop,
  .axie-fade,
  .axie-sheet-backdrop,
  .axie-sheet-panel,
  .axie-row-enter {
    animation: none;
  }

  .axie-pressable,
  .axie-pressable:hover,
  .axie-pressable:active {
    transform: none;
  }
}
